  3→const STORY_SELECT_COLUMNS = `
  4→    id,
  5→    author_id,
  6→    title,
  7→    description,
  8→    cover_url,
  9→    status,
 10→    tags,
 11→    privacy,
 12→    read_count,
 13→    vote_count,
 14→    created_at,
