309→// ── Reading Progress ──
310→export const saveProgressService = async (storyId, userId, chapterId, scrollPosition) => {
311→    if (!storyId || !userId || !chapterId) {
312→        throw { status: 400, error: 'storyId, userId, and chapterId are required' };
313→    }
314→
315→    // Check if this is a new reader (no existing progress for this user+story)
316→    const { data: existing } = await supabase
317→        .from('reading_progress')
318→        .select('id')
319→        .eq('user_id', userId)
320→        .eq('story_id', storyId)
321→        .maybeSingle();
322→
323→    const { data, error } = await supabase
324→        .from('reading_progress')
325→        .upsert({
326→            user_id: userId,
327→            story_id: storyId,
328→            chapter_id: chapterId,
329→            scroll_position: scrollPosition || 0,
330→            last_read_at: new Date().toISOString(),
331→        }, { onConflict: 'user_id,story_id' })
332→        .select('*')
333→        .single();
334→
335→    if (error) {
336→        console.error('supabase error saving progress:', error.message);
337→        throw { status: 500, error: 'failed to save progress' };
338→    }
339→
340→    // Increment read_count if this is a new reader (skip if author)
341→    if (!existing) {
342→        const { data: story } = await supabase
343→            .from('stories')
344→            .select('author_id')
345→            .eq('id', storyId)
346→            .single();
347→
348→        if (story && story.author_id !== userId) {
349→            const { error: rpcError } = await supabase.rpc('increment_story_reads', { story_id_input: storyId });
350→            if (rpcError) {
351→                console.error('error incrementing story reads:', rpcError.message);
352→            }
353→        }
354→    }
355→
356→    return data;
357→};
