  1→import React, { useState, useEffect, useRef, useCallback } from 'react';
  2→import { useNavigate, useParams, useLocation } from 'react-router-dom';
  3→import { useAuth } from '../../../Context/useAuth';
  4→import { useChapter, useChapterCommentCounts } from '../hooks/useStoryData';
  5→import { saveReadingProgress } from '../../../../API/StoryApi';
  6→import { motion, AnimatePresence } from 'framer-motion';
  7→import { BeatLoader } from 'react-spinners';
  8→import ParagraphCommentLayer from './ParagraphCommentLayer';
  9→import CommentPanel from './CommentPanel';
 10→
 11→import { LexicalComposer } from '@lexical/react/LexicalComposer';
 12→import { RichTextPlugin } from '@lexical/react/LexicalRichTextPlugin';
 13→import { ContentEditable } from '@lexical/react/LexicalContentEditable';
 14→import { LexicalErrorBoundary } from '@lexical/react/LexicalErrorBoundary';
 15→import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
 16→import { VIEWER_NODES, EDITOR_THEME } from '../../HomePage/Editor/editorConfig';
 17→
 18→import './ChapterReader.css';
 19→
 20→
 21→const ReaderContent = ({ chapter, onContentReady }) => {
 22→    const [editor] = useLexicalComposerContext();
 23→
 24→    useEffect(() => {
 25→        if (chapter?.content && editor) {
 26→            try {
 27→                const content = typeof chapter.content === 'string'
 28→                    ? chapter.content
 29→                    : JSON.stringify(chapter.content);
 30→                const state = editor.parseEditorState(content);
 31→                editor.setEditorState(state);
 32→            } catch (err) {
 33→                console.error('Failed to load chapter content:', err);
 34→            }
 35→            editor.setEditable(false);
 36→            if (onContentReady) onContentReady();
 37→        }
 38→    }, [chapter?.id, editor]);
 39→
 40→    return (
 41→        <RichTextPlugin
 42→            contentEditable={<ContentEditable className="chapter-reader-content" />}
 43→            ErrorBoundary={LexicalErrorBoundary}
 44→        />
 45→    );
 46→};
 47→
 48→const ChapterReader = () => {
 49→    const { storyId, chapterId } = useParams();
 50→    const navigate = useNavigate();
 51→    const location = useLocation();
 52→    const { session } = useAuth();
 53→    const token = session?.access_token;
 54→
 55→    const { data: chapter, isLoading } = useChapter(storyId, chapterId, token);
 56→    const { data: commentCounts } = useChapterCommentCounts(chapterId, token);
 57→    const progressTimerRef = useRef(null);
 58→    const scrollRef = useRef(0);
 59→    const bodyRef = useRef(null);
 60→    const hasRestoredRef = useRef(false);
 61→
 62→    // The scrollable element is .home-parent-container, not the window
 63→    const getScrollContainer = useCallback(() =>
 64→        document.querySelector('.home-parent-container') || document.documentElement
 65→    , []);
 66→    const [contentReady, setContentReady] = useState(false);
 67→    const [activeComment, setActiveComment] = useState(null);
 68→
 69→    // Save reading progress debounced on scroll
 70→    const saveProgress = useCallback(() => {
 71→        if (!token || !storyId || !chapterId) return;
 72→        saveReadingProgress(token, storyId, chapterId, scrollRef.current).catch(() => {});
 73→    }, [token, storyId, chapterId]);
 74→
 75→    useEffect(() => {
 76→        const container = getScrollContainer();
 77→
 78→        const handleScroll = () => {
 79→            const scrollTop = container.scrollTop;
 80→            const scrollableHeight = container.scrollHeight - container.clientHeight;
 81→            scrollRef.current = scrollableHeight > 0 ? Math.min(scrollTop / scrollableHeight, 1) : 0;
 82→
 83→            if (progressTimerRef.current) clearTimeout(progressTimerRef.current);
 84→            progressTimerRef.current = setTimeout(saveProgress, 3000);
 85→        };
 86→
 87→        container.addEventListener('scroll', handleScroll, { passive: true });
 88→        return () => {
 89→            container.removeEventListener('scroll', handleScroll);
 90→            if (progressTimerRef.current) clearTimeout(progressTimerRef.current);
 91→            // Save on unmount
 92→            saveProgress();
 93→        };
 94→    }, [saveProgress, getScrollContainer]);
 95→
 96→    // Restore scroll position when resuming from "Continue Reading"
 97→    useEffect(() => {
 98→        const savedPosition = location.state?.scrollPosition;
 99→        if (!savedPosition || hasRestoredRef.current || !contentReady) return;
100→        hasRestoredRef.current = true;
101→
102→        const container = getScrollContainer();
103→        // Double rAF ensures the browser has painted Lexical content
104→        let raf1, raf2;
105→        raf1 = requestAnimationFrame(() => {
106→            raf2 = requestAnimationFrame(() => {
107→                const scrollableHeight = container.scrollHeight - container.clientHeight;
108→                if (scrollableHeight > 0) {
109→                    container.scrollTo({ top: scrollableHeight * savedPosition, behavior: 'instant' });
110→                }
111→                navigate(location.pathname, { replace: true, state: {} });
112→            });
113→        });
114→
115→        return () => {
116→            cancelAnimationFrame(raf1);
117→            cancelAnimationFrame(raf2);
118→        };
119→    }, [contentReady]);
120→
121→    // Reset state when chapter changes
122→    useEffect(() => {
123→        setContentReady(false);
124→        setActiveComment(null);
125→    }, [chapterId]);
126→
127→    // Scroll progress bar (re-runs when chapter loads so the bar element exists in the DOM)
128→    useEffect(() => {
129→        const bar = document.getElementById('chapter-progress-bar');
130→        if (!bar) return;
131→        const container = getScrollContainer();
132→
133→        const updateBar = () => {
134→            const scrollTop = container.scrollTop;
135→            const scrollableHeight = container.scrollHeight - container.clientHeight;
136→            const pct = scrollableHeight > 0 ? (scrollTop / scrollableHeight) * 100 : 0;
137→            bar.style.width = `${Math.min(pct, 100)}%`;
138→        };
139→
140→        container.addEventListener('scroll', updateBar, { passive: true });
141→        return () => container.removeEventListener('scroll', updateBar);
142→    }, [getScrollContainer, isLoading]);
143→
144→    const editorConfig = {
145→        namespace: 'ChapterReader',
146→        theme: EDITOR_THEME,
147→        nodes: VIEWER_NODES,
148→        editable: false,
149→        onError(error) { console.error('Lexical error:', error); },
150→    };
151→
152→    if (isLoading) {
153→        return (
154→            <div className="chapter-reader">
155→                <div className="chapter-reader-loading">
156→                    <BeatLoader size={10} color="var(--text-muted)" />
157→                </div>
158→            </div>
159→        );
160→    }
161→
162→    if (!chapter) {
163→        return (
164→            <div className="chapter-reader">
165→                <p className="chapter-reader-error">Chapter not found.</p>
166→            </div>
167→        );
168→    }
169→
170→    const prevCh = chapter.prev_chapter;
171→    const nextCh = chapter.next_chapter;
172→
173→    return (
174→        <>
175→        {/* Progress bar — must be outside motion.div so position:fixed works */}
176→        <div className="chapter-progress-track">
177→            <div id="chapter-progress-bar" className="chapter-progress-fill" />
178→        </div>
179→
180→        <motion.div
181→            className="chapter-reader"
182→            initial={{ opacity: 0 }}
183→            animate={{ opacity: 1 }}
184→            transition={{ duration: 0.2 }}
185→        >
186→            {/* Header */}
187→            <div className="chapter-reader-header">
188→                <button
189→                    className="chapter-reader-back"
190→                    onClick={() => navigate(`/home/stories/${storyId}`)}
191→                >
192→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
193→                        <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
194→                    </svg>
195→                </button>
196→                <div className="chapter-reader-header-info">
197→                    <span className="chapter-reader-chapter-label">Chapter {chapter.chapter_number}</span>
198→                    <h1 className="chapter-reader-title">{chapter.title}</h1>
199→                </div>
200→            </div>
201→
202→            {/* Content */}
203→            <div className="chapter-reader-body" ref={bodyRef}>
204→                <LexicalComposer initialConfig={editorConfig}>
205→                    <ReaderContent chapter={chapter} onContentReady={() => setContentReady(true)} />
206→                </LexicalComposer>
207→                <ParagraphCommentLayer
208→                    containerRef={bodyRef}
209→                    commentCounts={commentCounts}
210→                    onParagraphClick={setActiveComment}
211→                />
212→            </div>
213→
214→            {/* Comment Panel */}
215→            <AnimatePresence>
216→                {activeComment && (
217→                    <CommentPanel
218→                        chapterId={chapterId}
219→                        activeComment={activeComment}
220→                        onClose={() => setActiveComment(null)}
221→                    />
222→                )}
223→            </AnimatePresence>
224→
225→            {/* Navigation */}
226→            <div className="chapter-reader-nav">
227→                {prevCh ? (
228→                    <button
229→                        className="chapter-nav-btn chapter-nav-prev"
230→                        onClick={() => navigate(`/home/stories/${storyId}/chapter/${prevCh.id}`)}
231→                    >
232→                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
233→                            <path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/>
234→                        </svg>
235→                        <span>Ch. {prevCh.chapter_number}: {prevCh.title}</span>
236→                    </button>
237→                ) : <div />}
238→                {nextCh ? (
239→                    <button
240→                        className="chapter-nav-btn chapter-nav-next"
241→                        onClick={() => navigate(`/home/stories/${storyId}/chapter/${nextCh.id}`)}
242→                    >
243→                        <span>Ch. {nextCh.chapter_number}: {nextCh.title}</span>
244→                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
245→                            <path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z"/>
246→                        </svg>
247→                    </button>
248→                ) : <div />}
249→            </div>
250→        </motion.div>
251→        </>
252→    );
253→};
254→
255→export default ChapterReader;
