  3→// ── Stories ──
  4→
  5→export const createStory = (token, formData) =>
  6→    authedFormRequest(token, 'POST', '/stories', formData, 'failed to create story');
  7→
  8→export const getStories = (limit = 10, before = null, status = null, tag = null, token = null) => {
  9→    const params = new URLSearchParams({ limit: String(limit) });
 10→    if (before) params.set('before', before);
 11→    if (status) params.set('status', status);
 12→    if (tag) params.set('tag', tag);
 13→    return token
 14→        ? authedGet(token, `/stories?${params}`, 'failed to fetch stories')
 15→        : publicGet(`/stories?${params}`, 'failed to fetch stories');
 16→};
