 18→export const getStoryById = (storyId, token = null) =>
 19→    token
 20→        ? authedGet(token, `/stories/${storyId}`, 'failed to fetch story')
 21→        : publicGet(`/stories/${storyId}`, 'failed to fetch story');
 22→
 23→export const updateStory = (token, storyId, formData) =>
 24→    authedFormRequest(token, 'PATCH', `/stories/${storyId}`, formData, 'failed to update story');
 25→
 26→export const deleteStory = (token, storyId) =>
