 43→    if (before) params.set('before', before);
 44→    return token
 45→        ? authedGet(token, `/stories/user/${userId}?${params}`, 'failed to fetch user stories')
 46→        : publicGet(`/stories/user/${userId}?${params}`, 'failed to fetch user stories');
