  1→import { useMutation, useQueryClient } from '@tanstack/react-query';
  2→import {
  3→    createStory,
  4→    updateStory,
  5→    deleteStory,
  6→    createChapter,
  7→    updateChapter,
  8→    deleteChapter,
  9→    reorderChapters,
 10→    toggleStoryVote,
 11→    toggleStoryLibrary,
 12→    addChapterComment,
 13→} from '../../../../API/StoryApi';
 14→
 15→export const useCreateStory = (token) => {
 16→    const queryClient = useQueryClient();
 17→    return useMutation({
 18→        mutationFn: (formData) => createStory(token, formData),
 19→        onSuccess: () => {
 20→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 21→        },
 22→    });
 23→};
 24→
 25→export const useUpdateStory = (token) => {
 26→    const queryClient = useQueryClient();
 27→    return useMutation({
 28→        mutationFn: ({ storyId, formData }) => updateStory(token, storyId, formData),
 29→        onSuccess: (_data, { storyId }) => {
 30→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 31→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
 32→        },
 33→    });
 34→};
 35→
 36→export const useDeleteStory = (token) => {
 37→    const queryClient = useQueryClient();
 38→    return useMutation({
 39→        mutationFn: (storyId) => deleteStory(token, storyId),
 40→        onSuccess: () => {
 41→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 42→        },
 43→    });
 44→};
 45→
 46→export const useCreateChapter = (token) => {
 47→    const queryClient = useQueryClient();
 48→    return useMutation({
 49→        mutationFn: ({ storyId, title }) => createChapter(token, storyId, title),
 50→        onSuccess: (_data, { storyId }) => {
 51→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
 52→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 53→        },
 54→    });
 55→};
 56→
 57→export const useUpdateChapter = (token) => {
 58→    const queryClient = useQueryClient();
 59→    return useMutation({
 60→        mutationFn: ({ storyId, chapterId, data }) => updateChapter(token, storyId, chapterId, data),
 61→        onSuccess: (_data, { storyId, chapterId }) => {
 62→            queryClient.invalidateQueries({ queryKey: ['chapter', storyId, chapterId] });
 63→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
 64→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 65→        },
 66→    });
 67→};
 68→
 69→export const useDeleteChapter = (token) => {
 70→    const queryClient = useQueryClient();
 71→    return useMutation({
 72→        mutationFn: ({ storyId, chapterId }) => deleteChapter(token, storyId, chapterId),
 73→        onSuccess: (_data, { storyId }) => {
 74→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
 75→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 76→        },
 77→    });
 78→};
 79→
 80→export const useReorderChapters = (token) => {
 81→    const queryClient = useQueryClient();
 82→    return useMutation({
 83→        mutationFn: ({ storyId, chapterOrder }) => reorderChapters(token, storyId, chapterOrder),
 84→        onSuccess: (_data, { storyId }) => {
 85→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
 86→        },
 87→    });
 88→};
 89→
 90→export const useToggleVote = (token) => {
 91→    const queryClient = useQueryClient();
 92→    return useMutation({
 93→        mutationFn: (storyId) => toggleStoryVote(token, storyId),
 94→        onMutate: async (storyId) => {
 95→            await queryClient.cancelQueries({ queryKey: ['story', storyId] });
 96→            const previous = queryClient.getQueryData(['story', storyId]);
 97→            if (previous) {
 98→                queryClient.setQueryData(['story', storyId], (old) => ({
 99→                    ...old,
100→                    has_voted: !old.has_voted,
101→                    vote_count: old.has_voted ? (old.vote_count || 1) - 1 : (old.vote_count || 0) + 1,
102→                }));
103→            }
104→            return { previous };
105→        },
106→        onError: (_err, storyId, context) => {
107→            if (context?.previous) {
108→                queryClient.setQueryData(['story', storyId], context.previous);
109→            }
110→        },
111→        onSettled: (_data, _err, storyId) => {
112→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
113→        },
114→    });
115→};
116→
117→export const useAddChapterComment = (token) => {
118→    const queryClient = useQueryClient();
119→    return useMutation({
120→        mutationFn: ({ chapterId, data }) => addChapterComment(token, chapterId, data),
121→        onSuccess: (_data, { chapterId }) => {
122→            queryClient.invalidateQueries({ queryKey: ['chapterComments', chapterId] });
123→            queryClient.invalidateQueries({ queryKey: ['chapterCommentCounts', chapterId] });
124→        },
125→    });
126→};
127→
128→export const useToggleLibrary = (token) => {
129→    const queryClient = useQueryClient();
130→    return useMutation({
131→        mutationFn: (storyId) => toggleStoryLibrary(token, storyId),
132→        onMutate: async (storyId) => {
133→            await queryClient.cancelQueries({ queryKey: ['story', storyId] });
134→            const previous = queryClient.getQueryData(['story', storyId]);
135→            if (previous) {
136→                queryClient.setQueryData(['story', storyId], (old) => ({
137→                    ...old,
138→                    in_library: !old.in_library,
139→                }));
140→            }
141→            return { previous };
142→        },
143→        onError: (_err, storyId, context) => {
144→            if (context?.previous) {
145→                queryClient.setQueryData(['story', storyId], context.previous);
146→            }
147→        },
148→        onSettled: (_data, _err, storyId) => {
149→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
150→            queryClient.invalidateQueries({ queryKey: ['myLibrary'] });
151→        },
152→    });
153→};
