 13→const STORY_SELECT_COLUMNS = `
 14→    id,
 15→    author_id,
 16→    title,
 17→    description,
 18→    cover_url,
 19→    status,
 20→    tags,
 21→    privacy,
 22→    read_count,
 23→    vote_count,
 24→    created_at,
 25→    updated_at
 26→`;
 27→
 28→const decorateAuthorSummary = (user, usage = 'card') => {
 29→    if(!user){
 30→        return user;
 31→    }
 32→
 33→    const avatarMedia = createMediaResponsePayload('avatars', user.image_url, usage);
 34→    return {
 35→        ...user,
 36→        image_url: avatarMedia?.preferred_url || user.image_url || null,
 37→        avatar_media: avatarMedia
 38→    };
 39→};
 40→
 41→const decorateStoryMedia = (story, usage = 'card') => {
 42→    if(!story){
 43→        return story;
 44→    }
 45→
 46→    const coverMedia = createMediaResponsePayload('story-covers', story.cover_url, usage);
 47→    return {
 48→        ...story,
 49→        cover_url: coverMedia?.preferred_url || story.cover_url || null,
 50→        cover_media: coverMedia
 51→    };
 52→};
