139→export const getStoriesService = async (limit, before, status, tag, userId) => {
140→    const parsedLimit = Math.min(Math.max(parseInt(limit) || 10, 1), 20);
141→
142→    let query = supabase
143→        .from('stories')
144→        .select(STORY_SELECT_COLUMNS)
145→        .eq('privacy', 'public')
146→        .order('created_at', { ascending: false })
147→        .limit(parsedLimit + 1);
148→
149→    if (before) {
150→        query = query.lt('created_at', before);
151→    }
152→    if (status && ['ongoing', 'completed', 'hiatus'].includes(status)) {
153→        query = query.eq('status', status);
154→    }
155→    if (tag) {
156→        query = query.contains('tags', [tag]);
157→    }
158→
159→    const { data, error } = await query;
160→
161→    if (error) {
162→        console.error('supabase error fetching stories:', error.message);
163→        throw { status: 500, error: 'failed to fetch stories' };
164→    }
165→
166→    if (!data || data.length === 0) {
167→        return { data: [], hasMore: false };
168→    }
169→
170→    // Batch-fetch author profiles
171→    const authorMap = await fetchAuthorProfiles(data.map(s => s.author_id));
172→
173→    // Fetch user interaction flags if logged in
174→    let userVotedSet = new Set();
175→    let userLibrarySet = new Set();
176→
177→    if (userId) {
178→        const storyIds = data.map(s => s.id);
